@spec vm_lane_drag_spec  src=tests/specs/vm_lane_drag_spec.lua  loc=526  sha=14993a2  cases=18
@exercises trackerView (h.vm), midiManager (h.fm), trackerManager (h.tm)
@surface   vm:setGridSize, vm:moveLaneEvent, fm:dump, tm:addEvent, tm:flush, tm:assignEvent, vm:addLaneEvent, vm:deleteLaneEvent, vm:cycleLaneShape, vm:setLaneTension
@harness   mk{seed.ccs, seed.notes}

# Intent
  Pins vm:moveLaneEvent: row-typed write surface for cc/pb/at events
  driven by the lane-strip drag in renderManager.
  
  Invariants:
    - integer toRow → ppq = toRow * logPerRow (the column frame is logical)
    - identity-by-index survives the post-flush rebuild, because:
        * tm sorts col.events by ppq each rebuild
        * the move clamps newppq strictly inside (prev.ppq, next.ppq) by ±1
    - fractional toRow (shift-drag) lands ppq off-grid, recording the
      authored fractional row so reswing remembers it
    - non cc/pb/at columns are silently ignored

# Helpers
  @fn findCcCol(vm, ccNum)  @ 15-19

# Cases
  @case 'integer toRow lands ppq on rowToPPQ exactly; identity-by-index preserved'  [harness]  @ 24-48
  @case 'toRow past previous event clamps to prev.ppq + 1'  [harness]  @ 52-70
  @case 'toRow past next event clamps to next.ppq - 1'  [harness]  @ 74-92
  @case 'fractional toRow (shift-drag) lands ppq off-grid'  [harness]  @ 96-115
  @case 'non-cc/pb/at column is a no-op'  [harness]  @ 119-135
  @case 'val updates without ppq change when toRow matches current row'  [harness]  @ 139-157
  @case 'real pb drags past hidden fake pb at lane-1 note seat'  [harness]  @ 167-215
  @case 'real pb dropped exactly on hidden fake pb seat — fake gets promoted, no loss'  [harness]  @ 226-269
  @case 'pb drag preserves shape and tension'  [harness]  @ 277-311
  @case 'addLaneEvent between two events inherits prev shape, returns idx 2'  [harness]  @ 321-347
  @case 'addLaneEvent before first event has no prev → idx 1, nil shape'  [harness]  @ 351-370
  @case 'addLaneEvent on non-renderable col is a no-op'  [harness]  @ 374-387
  @case 'deleteLaneEvent removes the named visible event'  [harness]  @ 393-414
  @case 'deleteLaneEvent on non-renderable col is a no-op'  [harness]  @ 418-433
  @case 'cycleLaneShape advances shape on the named visible event'  [harness]  @ 440-459
  @case 'cycleLaneShape on non-renderable col is a no-op'  [harness]  @ 463-477
  @case 'setLaneTension writes tension and forces shape=bezier'  [harness]  @ 484-506
  @case 'setLaneTension on non-renderable col is a no-op'  [harness]  @ 510-524

